import{_ as t,o as i,c as r,a2 as a}from"./chunks/framework.B72_uj9U.js";const g=JSON.parse('{"title":"Droid — Unique Patterns","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/droid/unique-patterns.md","filePath":"research/agents/droid/unique-patterns.md"}'),n={name:"research/agents/droid/unique-patterns.md"};function o(s,e,l,d,c,u){return i(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="droid-—-unique-patterns" tabindex="-1">Droid — Unique Patterns <a class="header-anchor" href="#droid-—-unique-patterns" aria-label="Permalink to &quot;Droid — Unique Patterns&quot;">​</a></h1><blockquote><p>What makes Droid architecturally and strategically distinct: interface agnosticism, enterprise-native design, model/vendor independence, and async delegation across surfaces.</p></blockquote><h2 id="_1-interface-agnostic-architecture" tabindex="-1">1. Interface-Agnostic Architecture <a class="header-anchor" href="#_1-interface-agnostic-architecture" aria-label="Permalink to &quot;1. Interface-Agnostic Architecture&quot;">​</a></h2><p><strong>The most distinctive pattern in Droid&#39;s design is that the same agent operates across every developer surface.</strong></p><p>While the industry has fragmented into surface-specific agents — Cursor for IDE, Claude Code for terminal, Devin for web workspaces, various bots for Slack/CI — Factory built a single agent core that deploys to all of them:</p><table tabindex="0"><thead><tr><th>Interface</th><th>Use Pattern</th></tr></thead><tbody><tr><td><strong>IDE</strong></td><td>Inline coding assistance, real-time pair programming</td></tr><tr><td><strong>Web</strong></td><td>Cloud workspaces for complex tasks, accessible from anywhere</td></tr><tr><td><strong>CLI</strong></td><td>Terminal-native for power users, local dev, scripting</td></tr><tr><td><strong>Slack</strong></td><td>Delegate tasks from team chat without context switching</td></tr><tr><td><strong>Linear</strong></td><td>Pick up tasks directly from project management</td></tr><tr><td><strong>Microsoft Teams</strong></td><td>Enterprise communication integration</td></tr><tr><td><strong>CI/CD</strong></td><td>Non-interactive pipeline automation (auto-review, repair)</td></tr></tbody></table><h3 id="why-this-matters" tabindex="-1">Why This Matters <a class="header-anchor" href="#why-this-matters" aria-label="Permalink to &quot;Why This Matters&quot;">​</a></h3><p>This isn&#39;t just a convenience feature — it&#39;s an architectural decision with deep implications:</p><ol><li><p><strong>Session continuity across surfaces</strong>: A task started in Slack can be monitored in web and finalized in CLI. The compaction engine preserves context across transitions.</p></li><li><p><strong>Unified analytics</strong>: Factory Analytics captures tool usage, token spend, and productivity metrics uniformly regardless of interface. This enables apples-to-apples comparison of delegation patterns across surfaces.</p></li><li><p><strong>Enterprise deployment simplicity</strong>: IT teams deploy one platform, not seven different tools with separate security, audit, and compliance configurations.</p></li><li><p><strong>Workflow-native delegation</strong>: Developers delegate tasks where they encounter them. See a bug in PagerDuty → delegate via Slack. Review a spec in Linear → delegate implementation. This reduces the friction of &quot;switching to the AI tool.&quot;</p></li></ol><h3 id="activity-tracking-by-client" tabindex="-1">Activity Tracking by Client <a class="header-anchor" href="#activity-tracking-by-client" aria-label="Permalink to &quot;Activity Tracking by Client&quot;">​</a></h3><p>Factory Analytics breaks down usage by client type:</p><ul><li>Terminal CLI</li><li>Non-interactive CI mode</li><li>Web workspaces</li></ul><p><strong>Stickiness</strong> (DAU/MAU ratio) reveals whether AI tooling is embedded in daily workflow or used occasionally — a critical enterprise adoption metric.</p><h2 id="_2-enterprise-native-design-not-enterprise-bolted" tabindex="-1">2. Enterprise-Native Design (Not Enterprise-Bolted) <a class="header-anchor" href="#_2-enterprise-native-design-not-enterprise-bolted" aria-label="Permalink to &quot;2. Enterprise-Native Design (Not Enterprise-Bolted)&quot;">​</a></h2><p>Most coding agents were built for individual developers and later added enterprise features. Factory built enterprise-first:</p><h3 id="factory-analytics" tabindex="-1">Factory Analytics <a class="header-anchor" href="#factory-analytics" aria-label="Permalink to &quot;Factory Analytics&quot;">​</a></h3><p>A full observability platform built on <strong>OpenTelemetry</strong> — not an afterthought dashboard:</p><table tabindex="0"><thead><tr><th>Analytics View</th><th>Metrics</th></tr></thead><tbody><tr><td><strong>Tokens</strong></td><td>Consumption by model, user, date; input/output split; cache efficiency</td></tr><tr><td><strong>Tools</strong></td><td>Tool calls by type; skills/slash commands/MCP adoption; autonomy ratio</td></tr><tr><td><strong>Activity</strong></td><td>DAU/WAU/MAU; sessions/messages; client breakdown; stickiness</td></tr><tr><td><strong>Productivity</strong></td><td>Files created/edited; commits; PRs; language distribution</td></tr><tr><td><strong>Users</strong></td><td>Per-person breakdowns; days active; tokens; tool calls; sessions</td></tr></tbody></table><p>The Analytics API enables a powerful second-order pattern: <strong>Droids generating their own ROI reports</strong>. Droids can:</p><ul><li>Call <code>/analytics/activity</code>, <code>/analytics/tokens</code>, <code>/analytics/productivity</code>, <code>/analytics/tools</code></li><li>Join with Jira/Linear data</li><li>Generate narratives like &quot;team doubled PR merge rate in the sprint they ramped Droid usage&quot;</li><li>Package these into leadership-ready reports automatically</li></ul><h3 id="audit-and-compliance" tabindex="-1">Audit and Compliance <a class="header-anchor" href="#audit-and-compliance" aria-label="Permalink to &quot;Audit and Compliance&quot;">​</a></h3><ul><li><strong>ISO 42001</strong>: Among the first organizations worldwide to adopt the AI management system standard.</li><li><strong>SOC 2 Type I</strong>: Achieved certification for security and privacy controls.</li><li><strong>Droid Shield</strong>: Proprietary system for detecting and removing security vulnerabilities, bugs, or IP breaches from generated code.</li><li><strong>Audit logging</strong>: Comprehensive, configurable, exportable to SIEM systems.</li><li><strong>No training on customer data</strong>: Explicit commitment that customer code is never used as model training data.</li><li><strong>Single-tenant VPC</strong>: Each organization gets isolated, sandboxed compute.</li></ul><h3 id="enterprise-security-stack" tabindex="-1">Enterprise Security Stack <a class="header-anchor" href="#enterprise-security-stack" aria-label="Permalink to &quot;Enterprise Security Stack&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>Implementation</th></tr></thead><tbody><tr><td>Authentication</td><td>SSO + SAML + OIDC (Google Workspace, Okta, Azure AD)</td></tr><tr><td>Provisioning</td><td>SCIM automated user lifecycle</td></tr><tr><td>Compute</td><td>Dedicated allocation per organization</td></tr><tr><td>Data at rest</td><td>AES-256 encryption</td></tr><tr><td>Data in transit</td><td>TLS 1.2+</td></tr><tr><td>Permissions</td><td>Mirrors source application access controls</td></tr><tr><td>Hosting</td><td>Single-tenant sandboxed VPC</td></tr><tr><td>Code safety</td><td>Droid Shield vulnerability/IP detection</td></tr></tbody></table><h3 id="agent-readiness-program" tabindex="-1">Agent-Readiness Program <a class="header-anchor" href="#agent-readiness-program" aria-label="Permalink to &quot;Agent-Readiness Program&quot;">​</a></h3><p>Factory offers an <strong>Agent-Readiness Improvement Program</strong> for enterprise customers — suggesting they actively consult on how to optimize organizations for AI-native development, not just sell software.</p><h2 id="_3-model-vendor-agnostic-design" tabindex="-1">3. Model/Vendor Agnostic Design <a class="header-anchor" href="#_3-model-vendor-agnostic-design" aria-label="Permalink to &quot;3. Model/Vendor Agnostic Design&quot;">​</a></h2><p>Droid works with <strong>any model provider</strong>: OpenAI, Anthropic, Google, xAI, open-source, and local models.</p><h3 id="strategic-implications" tabindex="-1">Strategic Implications <a class="header-anchor" href="#strategic-implications" aria-label="Permalink to &quot;Strategic Implications&quot;">​</a></h3><ul><li><strong>No vendor lock-in</strong>: As model capabilities shift (and they shift rapidly), enterprises aren&#39;t trapped on a single provider.</li><li><strong>Cost optimization</strong>: Teams can route different task types to different models: <ul><li>Frontier models (Opus 4.6, o3-pro) for complex reasoning, spec generation</li><li>Cost-efficient models (GLM-5, Kimi-K2.5) for routine execution</li><li>Open-source/local models for sensitive code that can&#39;t leave the network</li></ul></li><li><strong>Day-one model access</strong>: Factory&#39;s pricing page promises &quot;fast and direct priority routing, the day the model is available.&quot;</li><li><strong>Mixed-model Specification Mode</strong>: Planning with one model, execution with another.</li></ul><h3 id="terminal-bench-evidence" tabindex="-1">Terminal-Bench Evidence <a class="header-anchor" href="#terminal-bench-evidence" aria-label="Permalink to &quot;Terminal-Bench Evidence&quot;">​</a></h3><p>Droid&#39;s benchmark results demonstrate model flexibility:</p><ul><li>GPT-5.3-Codex: 77.3% (rank #6)</li><li>Claude Opus 4.6: 69.9% (rank #16)</li><li>GPT-5.2: 64.9% (rank #23)</li><li>Claude Opus 4.1 (v1.0): 58.8% (rank #5)</li></ul><p>The agent platform maintains competitive performance across model families rather than being optimized for a single provider.</p><h2 id="_4-long-running-async-task-delegation" tabindex="-1">4. Long-Running Async Task Delegation <a class="header-anchor" href="#_4-long-running-async-task-delegation" aria-label="Permalink to &quot;4. Long-Running Async Task Delegation&quot;">​</a></h2><p>Droid handles tasks that span from minutes to weeks:</p><h3 id="short-lived-tasks-minutes" tabindex="-1">Short-Lived Tasks (Minutes) <a class="header-anchor" href="#short-lived-tasks-minutes" aria-label="Permalink to &quot;Short-Lived Tasks (Minutes)&quot;">​</a></h3><ul><li>Inline code review comments</li><li>Quick refactors</li><li>Test generation for a single file</li></ul><h3 id="medium-tasks-hours" tabindex="-1">Medium Tasks (Hours) <a class="header-anchor" href="#medium-tasks-hours" aria-label="Permalink to &quot;Medium Tasks (Hours)&quot;">​</a></h3><ul><li>Full PR reviews with guideline compliance</li><li>CI failure diagnosis and repair</li><li>Cross-file refactoring</li></ul><h3 id="long-running-tasks-days-to-weeks" tabindex="-1">Long-Running Tasks (Days to Weeks) <a class="header-anchor" href="#long-running-tasks-days-to-weeks" aria-label="Permalink to &quot;Long-Running Tasks (Days to Weeks)&quot;">​</a></h3><p>This is where Droid&#39;s compaction engine becomes critical:</p><ul><li><strong>Multi-repository migrations</strong> (Chainguard: 6 repos, 2 weeks, 80 packages)</li><li><strong>Feature development from spec to PR</strong></li><li><strong>Iterative design → implement → review → revise cycles</strong></li></ul><p>The key architectural pattern: <strong>session state is decoupled from any single interface session</strong>. The Droid session persists server-side, and any interface can attach to it. This means:</p><ol><li>Developer delegates a migration task via Slack.</li><li>Droid begins executing, running for hours in background.</li><li>Developer checks progress in web workspace the next day.</li><li>Developer provides feedback via CLI.</li><li>Droid continues, eventually opening PRs across 6 repos.</li><li>Developer reviews PRs in GitHub, provides review comments.</li><li>Droid addresses review feedback and merges.</li></ol><p>All within a single continuous session, with full context preservation.</p><h2 id="_5-droid-shield-—-code-safety-system" tabindex="-1">5. &quot;Droid Shield&quot; — Code Safety System <a class="header-anchor" href="#_5-droid-shield-—-code-safety-system" aria-label="Permalink to &quot;5. &quot;Droid Shield&quot; — Code Safety System&quot;">​</a></h2><p>A unique pattern in the enterprise security space:</p><ul><li>Performs <strong>industry-leading techniques</strong> to detect and remove security vulnerabilities from generated code.</li><li>Scans for bugs and IP breaches in generated output.</li><li>Acts as a guardrail between the LLM&#39;s output and the codebase.</li><li>Addresses the enterprise concern: &quot;how do we trust AI-generated code?&quot;</li></ul><h2 id="_6-the-wipro-pattern-—-enterprise-channel-strategy" tabindex="-1">6. The Wipro Pattern — Enterprise Channel Strategy <a class="header-anchor" href="#_6-the-wipro-pattern-—-enterprise-channel-strategy" aria-label="Permalink to &quot;6. The Wipro Pattern — Enterprise Channel Strategy&quot;">​</a></h2><p>Factory&#39;s partnership with Wipro (NYSE: WIT) reveals a distinctive go-to-market pattern:</p><ul><li>Wipro integrates Factory into its <strong>WEGA agent-native delivery platform</strong>.</li><li>Rollout across <strong>tens of thousands of engineers</strong>.</li><li>Factory becomes embedded in Wipro&#39;s service delivery to clients across banking, healthcare, manufacturing, retail, and technology.</li><li>Wipro Ventures participated in Factory&#39;s funding round.</li></ul><p>This is notable because most AI coding tools sell direct-to-developer or direct-to-enterprise. Factory is also selling through <strong>systems integrators</strong> — a classic enterprise software distribution pattern rarely seen in the AI agent space.</p><h2 id="_7-productivity-metrics-as-first-class-citizens" tabindex="-1">7. Productivity Metrics as First-Class Citizens <a class="header-anchor" href="#_7-productivity-metrics-as-first-class-citizens" aria-label="Permalink to &quot;7. Productivity Metrics as First-Class Citizens&quot;">​</a></h2><p>Factory doesn&#39;t just track whether developers use Droid — it tracks <strong>engineering outcomes</strong>:</p><table tabindex="0"><thead><tr><th>Claimed Metric</th><th>Value</th></tr></thead><tbody><tr><td>Feature delivery speed</td><td>7x faster</td></tr><tr><td>Migration time reduction</td><td>96.1%</td></tr><tr><td>On-call resolution time saved</td><td>95.8%</td></tr></tbody></table><p>These metrics flow into the Analytics platform, where they can be correlated with AI usage data, creating a feedback loop:</p><ul><li>More delegation → measure impact → optimize delegation patterns → more effective delegation.</li></ul><p>This is a pattern unique to enterprise-focused agents. Individual developer tools measure &quot;did the suggestion get accepted?&quot; Factory measures &quot;did the project ship faster?&quot;</p>',59)])])}const h=t(n,[["render",o]]);export{g as __pageData,h as default};
